-- Fix Barossa projects: NT → OFFSHORE_AU (offshore WA waters, not NT onshore)
UPDATE projects SET projectState = 'OFFSHORE_AU' WHERE id IN ('120230', '510034', '4');

-- Reactivate Woodside Scarborough (was suppressed/stale)
UPDATE projects SET lifecycleStatus = 'active', suppressed = 0 WHERE id = '7';

-- Reactivate Scarborough Gas Project (was stale)
UPDATE projects SET lifecycleStatus = 'active' WHERE id = '120229';

-- Verify all changes
SELECT id, name, projectState, lifecycleStatus, suppressed FROM projects
WHERE id IN ('120230', '510034', '4', '7', '120229')
ORDER BY id;

